class Solution {
public:
    bool uniqueOccurrences(vector<int>& arr) {
        unordered_map<int, int> count;
        for (int num : arr) {
            count[num]++;
        }
        unordered_set<int> occurrences;
        for (auto it : count) {
            if (occurrences.count(it.second)) {
                return false;
            }
            occurrences.insert(it.second);
        }
        return true;
    }
};
```
